=span-grid($span, $location: $grid-counter, $columns: $columns, $gutter: $gutter)
  float: left
  width: grid-span($span, $location, $columns, $gutter)
  $grid-counter: $location + $span
  @if $grid-counter > column-count($columns)
    $grid-counter: 1
  @else
    margin-right: $gutter
    @debug $grid-counter

